INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'inspeccion', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza verificación de equipo en el servicio se observa que el equipo se encuentra roto, motivo por el cual se atiende llamado. Se informa a la jefe del servicio que el equipo va a ser retirado ya que no cumple con las condiciones adecuadas para el uso en el servicio.   Equipo se trata de pegar, pero se fractura por el mismo punto a la hora de realizar pruebas funcionales.   Se recomienda dar de baja el equipo ya que su estructura esta rota y en mal estado de funcionamiento Fe' FROM equipos WHERE codigo_inventario = 'BFE-FOTOF-00015810' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza revisión de laringoscopio, se encuentra bombillo fundido.   Se realiza cambio del bombillo y pruebas funcionales satisfactorias' FROM equipos WHERE codigo_inventario = 'BAN-LARIN-00012962' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'inspeccion', 'completado', '2014-10-30', '-NO_DEFINIDO - se realiza verificación de equipo, se observa que el equipo se encuentra bastante deteriorado, el servicio informa que el equipo se encontraba en un mueble bajo llave y que se encontraba fuera de servicio desde hace muchos años. se recomienda dar de baja el equipo ya que su estructura está rota y en mal estado de funcionamiento' FROM equipos WHERE codigo_inventario = 'BFE-FOTOF-00000625' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza revisión del equipo, encontrando daño en el brazo del fotóforo lo cual ocasionó exposición de los cables y daño del equipo dejándolo fuera de servicio, se realiza cambio de carcaza para extender su vida útil. se entrega equipo al servicio en funcionamiento, se recomienda realizar el uso adecuado del equipo para garantizar su correcto funcionamiento, se adjunta registro fotográfico del daño encontrado. se entrega para su respectiva limpieza y desinfección.' FROM equipos WHERE codigo_inventario = 'BFE-FOTOF-00015060' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
