INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se evidencia durante la ronda realizada en salas de cirugía de la sala 7 que el sensor de oximetría no funciona.  Se procede a realizar la respectiva revisión en donde se evidencia filtración de liquidos en el conector entre la interfaz y el sensor de saturación. Se procede a realizar limpieza secado de contactos , se realizan pruebas evidenciando que el oxímetro sigue sin funcionar, por lo cual se realiza cambio de interfaz y sensor de oximetría se realizan pruebas de funcionamie' FROM equipos WHERE codigo_inventario = 'BMO-MOSIV-00015471' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se revisa equipo y se encuentra sensor de spo2 e interfaz  que no funcionan, al revisar se encuentra que estos tienen líquidos en sus conectores, se realiza secado con aire de instrumental se realiza la prueba pero estos no funcionan adecuadamente por lo cual se realiza el cambio del sensor y de la interfaz por unos nuevos y equipo queda funcionando correctamente' FROM equipos WHERE codigo_inventario = 'BMO-MOSIV-00015471' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
