INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza traslado de cabina y equipos audiómetro e impedansiometro del área de consulta externa a rehabilitación. Se realizan pruebas de funcionamiento y equipos quedan funcionando correctamente  Se adjunta reporte de sericio' FROM equipos WHERE codigo_inventario = 'BFA-IMPED-00013008' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - CREADA DESDE AMsi  23/10/2020: Se asiste al servicio de urgencias pero el equipo no esta en la sala era por lo cual se solicita que cuando el equipo este desocupado nos informen para realizar el ajuste  26/10/2020: Se realiza ajuste del adaptador del ventilador a la base de este quedando cargador asegurado de una mejor forma. se entrega al servicio en buenas condiciones.' FROM equipos WHERE codigo_inventario = 'BVN-VENTI-00013774' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'calibracion', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza revisión del equipo por problema reportado (El ventilador deja de ciclar durante funcionamiento con paciente). Se realiza revisión general del equipo evidenciando que pasa las pruebas iniciales y de ciclado con éxito. Sin embargo, se realiza retiro del ventilador al laboratorio de Draeger con el fin de realizar pruebas más detalladas en periodos de tiempos más extensos, por tratarse de un posible error aleatorio. El equipo se deja en pruebas de ciclado durante 2 semanas' FROM equipos WHERE codigo_inventario = 'BVN-VENTI-00013774' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'inspeccion', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza revisión del ventilador ejecutando el chequeo general con resultados optamos.  Se verifica el historial de errores evidenciando avisos de batería baja y flujo bajo de oxigeno.  Se realiza calibración de válvula peep,sensores de flujo, sensores de presión y sensores de ambiente.  Se realizan pruebas de funcionamiento en cada uno de los modos ventilatorios por mas de 40 min con resultados satisfactorios.  Se recomienda verificar las tomas donde se conecta el equipo y mant' FROM equipos WHERE codigo_inventario = 'BVN-VENTI-00013774' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza entrega e instalación de los dos sensores de flujo internos y una de las válvulas de dosificación por diagnostico anterior. Se realiza desarme del equipo y reemplazo de las partes afectadas. Se realizan pruebas de funcionamiento sobre las partes nuevas.  Se realizan pruebas de funcionamiento general, pruebas iniciales, pruebas de ciclado y modos ventilatorios con éxito. El equipo no presenta fallas. El equipo cumple con los parámetros para ser usado en pacientes.  EQUIP' FROM equipos WHERE codigo_inventario = 'BVN-VENTI-00013774' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'correctivo', 'completado', '2014-10-30', '-NO_DEFINIDO - Se realiza entrega e instalación de carcasa frontal por diagnostico anterior. Se realiza desarme del equipo y reemplazo de la carcasa dañada. Se realiza rearmado del equipo y pruebas de funcionamiento general con éxito. El equipo se encuentra en buen estado y correcto funcionamiento.  EQUIPO OPERATIVO  Se adjunta reporte de servicio' FROM equipos WHERE codigo_inventario = 'BVN-VENTI-00013774' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
