INSERT INTO mantenimientos (institucion_id, equipo_id, tipo, estado, fecha_programada, descripcion) SELECT '00000000-0000-0000-0000-000000000001', id, 'calibracion', 'completado', '2014-10-30', '-NO_DEFINIDO - Se recibe el equipo con reporte de falla de volúmenes altos, se procede a realizar comprobación del equipo la cual pasa satisfactoriamente, mediante el menú de servicio se realiza calibración de sensores de flujo, válvulas de seguridad e inspiratoria, pasando correctamente, adicional tampoco se evidencia ningún registro de errores.  Se deja en prueba con modo controlado en diferentes configuraciones de volúmenes, frecuencias y presiones sin presentar fallos.' FROM equipos WHERE codigo_inventario = 'BVN-VENTI-00013774' AND institucion_id = '00000000-0000-0000-0000-000000000001' LIMIT 1;
